ps.pstext:
if !IsFeatureImplemented(FEAT_SVE2) && !IsFeatureImplemented(FEAT_SME) then
    EndOfDecode(Decode_UNDEF);
end;
if size == '00' then EndOfDecode(Decode_UNDEF); end;
let esize : integer{} = 8 << UInt(size);
let g : integer = UInt(Pg);
let m : integer = UInt(Zm);
let dn : integer = UInt(Zdn);

CheckSVEEnabled();
let VL : integer{} = CurrentVL();
let PL : integer{} = VL DIV 8;
let elements : integer = VL DIV esize;
let mask : bits(PL) = P{}(g);
let operand1 : bits(VL) = Z{}(dn);
let operand2 : bits(VL) = if AnyActiveElement{PL}(mask, esize) then Z{VL}(m) else Zeros{VL};
var result : bits(VL) = Z{}(dn);
var element1 : bits(esize);
var element2 : bits(esize);

for e = 0 to elements-1 do
    if ActivePredicateElement{PL}(mask, e, esize) then
        if IsEven(e) then
            element1 = operand1[(e + 0)*:esize];
            element2 = operand1[(e + 1)*:esize];
        else
            element1 = operand2[(e - 1)*:esize];
            element2 = operand2[(e + 0)*:esize];
        end;
        result[e*:esize] = FPMin{esize}(element1, element2, FPCR());
    end;
end;

Z{VL}(dn) = result;
